/**
 * @summary Get daily appointment counts
 */
export const getGetDailyReportUrl = (params: GetDailyReportParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/daily?${stringifiedParams}`
    : `/api/reports/daily`;
};

export const getDailyReport = async (
  params: GetDailyReportParams,
  options?: RequestInit,
): Promise<DailyReportItem[]> => {
  return customFetch<DailyReportItem[]>(getGetDailyReportUrl(params), {
    ...options,
    method: "GET",
  });
};

